// 2. Variáveis de Estado da Aplicação
let paragensAtuais = [];
let fichasGuardadas = JSON.parse(localStorage.getItem("fichas_vamus") || "[]");
let indiceEdicao = -1; 
let pagManual = { D: 0, C: 0, A: 0 };
let fotosAtuais = { matricula_foto: "", rota_vamus: "", samsung_cycling: "", foto: "" };

const configFotos = [
  { inputId: "matricula_foto", previewId: "preview_matricula" },
  { inputId: "rota_vamus", previewId: "preview_rota_vamus" },
  { inputId: "samsung_cycling", previewId: "preview_samsung_cycling" },
  { inputId: "foto", previewId: "preview" }
];

// 3. Inicialização ao Carregar o DOM
document.addEventListener("DOMContentLoaded", () => {
  povoarSeletorCarreiras();
  configurarListenersImagens();
  renderFichasGuardadas();

  // Monitorização dinâmica da alteração do seletor de carreiras
  const select = document.getElementById("carreiraSelect");
  select.addEventListener("change", (e) => {
    let customInput = document.getElementById("carreira_manual_input");
    
    if (e.target.value === "manual_custom") {
      if (!customInput) {
        customInput = document.createElement("input");
        customInput.type = "text";
        customInput.id = "carreira_manual_input";
        customInput.placeholder = "Digita a Linha (ex: Linha 10 - Faro - Loulé)";
        customInput.style.marginTop = "8px";
        customInput.style.display = "block";
        e.target.parentNode.insertBefore(customInput, e.target.nextSibling);
      } else {
        customInput.style.display = "block";
      }
    } else {
      if (customInput) {
        customInput.style.display = "none";
        customInput.value = "";
      }
    }
    gerarTabelaHorario();
  });

  document.getElementById("data_viagem").addEventListener("change", () => {
    gerarTabelaHorario();
  });
});

function povoarSeletorCarreiras() {
  const select = document.getElementById("carreiraSelect");
  select.innerHTML = '<option value="">-- Escolher carreira --</option>';
  Object.keys(baseDadosHorarios).forEach(carreira => {
    select.innerHTML += `<option value="${carreira}">${carreira}</option>`;
  });
  select.innerHTML += '<option value="manual_custom">Outra Linha (Inserção Manual)...</option>';
}

function obterTipoDia(dataStr) {
  if (!dataStr) return "Dias Úteis";
  const diaSemana = new Date(dataStr).getDay();
  if (diaSemana === 0) return "Domingo e Feriado";
  if (diaSemana === 6) return "Sábado";
  return "Dias Úteis";
}

// 4. Geração Dinâmica da Tabela com Base de Dados do Horário
window.gerarTabelaHorario = function() {
  const carreira = document.getElementById("carreiraSelect").value;
  const sentido = document.getElementById("sentido").value;
  const data_viagem = document.getElementById("data_viagem").value;
  const tipoDia = obterTipoDia(data_viagem);

  const painel = document.getElementById("painelTabelaHorario");
  const avisoSemHorario = document.getElementById("avisoSemHorario");

  if (!carreira) {
    painel.innerHTML = "";
    avisoSemHorario.style.display = "none";
    return;
  }

  // Se for uma linha manual (fora da BD), limpamos a tabela fixa e oferecemos introdução limpa
  if (carreira === "manual_custom") {
    avisoSemHorario.style.display = "none";
    painel.innerHTML = `
      <div style="background: #eef1f6; padding: 12px; border-radius: 6px; margin-bottom: 12px; border: 1px solid #dcdfe6; line-height: 1.4;">
        <p style="margin: 0 0 5px 0; font-weight: bold; color: #1e293b;">Linha Personalizada Ativa</p>
        <span style="font-size: 12px; color: #64748b;">Como esta linha não tem base de dados local, podes criar e registar cada paragem livremente através do formulário <strong>"Adicionar Paragem Manual"</strong> abaixo à medida que o percurso acontece.</span>
      </div>
    `;
    paragensAtuais = [];
    return;
  }

  const dadosLinha = baseDadosHorarios[carreira]?.[sentido]?.[tipoDia] || baseDadosHorarios[carreira]?.[sentido]?.["Dias Úteis"];

  if (!dadosLinha) {
    painel.innerHTML = "";
    avisoSemHorario.style.display = "block";
    return;
  }

  avisoSemHorario.style.display = "none";

  let html = `
    <div style="background: #eef1f6; padding: 10px; border-radius: 6px; margin-bottom: 12px; border: 1px solid #dcdfe6;">
      <label style="margin-top:0;"><strong>Selecionar Viagem (Hora Partida):</strong></label>
      <select id="runSelect" onchange="carregarParagensDaViagem()" style="margin-bottom: 5px;">
        ${dadosLinha.runs.map(r => `<option value="${r}">Partida às ${r}</option>`).join("")}
      </select>
    </div>
    <div class="tabela-wrap">
      <table class="tabela-paragens">
        <thead>
          <tr>
            <th>Paragem</th>
            <th style="width: 70px;">Teórica</th>
            <th style="width: 105px;">Real</th>
            <th style="width: 110px;">Pax (D / C / A)</th>
            <th>Obs / Eventos</th>
          </tr>
        </thead>
        <tbody id="corpoTabelaParagens"></tbody>
      </table>
    </div>
  `;
  painel.innerHTML = html;
  carregarParagensDaViagem();
};

window.carregarParagensDaViagem = function() {
  const carreira = document.getElementById("carreiraSelect").value;
  if (carreira === "manual_custom") return;

  const sentido = document.getElementById("sentido").value;
  const data_viagem = document.getElementById("data_viagem").value;
  const tipoDia = obterTipoDia(data_viagem);
  const runIndex = document.getElementById("runSelect").selectedIndex;

  const dadosLinha = baseDadosHorarios[carreira]?.[sentido]?.[tipoDia] || baseDadosHorarios[carreira]?.[sentido]?.["Dias Úteis"];
  if (!dadosLinha) return;

  const tbody = document.getElementById("corpoTabelaParagens");
  tbody.innerHTML = "";

  paragensAtuais = dadosLinha.stops.map(stop => {
    const tPrevista = stop.times[runIndex] || "--";
    return {
      nome: stop.name,
      horaPrevista: tPrevista,
      horaReal: "",
      dinheiro: 0,
      cartao: 0,
      app: 0,
      obs: ""
    };
  });

  paragensAtuais.forEach((item, index) => {
    tbody.innerHTML += renderizarLinhaParagem(item, index);
  });
};

function renderizarLinhaParagem(item, index) {
  return `
    <tr>
      <td><strong>${item.nome}</strong></td>
      <td><span class="hora-prevista">${item.horaPrevista}</span></td>
      <td>
        <div style="display:flex; gap:3px; align-items:center;">
          <input type="time" id="real_time_${index}" value="${item.horaReal}" onchange="atualizarCampoTabela(${index}, 'horaReal', this.value)" style="padding: 4px; font-size:12px; margin-top:0;">
          <button type="button" class="btn-mini btn-mais" onclick="definirHoraAtual(${index})" title="Hora Atual" style="height:26px; width:26px; font-size:11px;">⏱️</button>
        </div>
      </td>
      <td>
        <div class="pag-linha">
          <span class="pag-label">D</span>
          <button type="button" class="btn-mini btn-menos" onclick="alterarPax(${index}, 'dinheiro', -1)">-</button>
          <span id="pax_${index}_dinheiro" class="pag-valor">${item.dinheiro}</span>
          <button type="button" class="btn-mini btn-mais" onclick="alterarPax(${index}, 'dinheiro', 1)">+</button>
        </div>
        <div class="pag-linha">
          <span class="pag-label">C</span>
          <button type="button" class="btn-mini btn-menos" onclick="alterarPax(${index}, 'cartao', -1)">-</button>
          <span id="pax_${index}_cartao" class="pag-valor">${item.cartao}</span>
          <button type="button" class="btn-mini btn-mais" onclick="alterarPax(${index}, 'cartao', 1)">+</button>
        </div>
        <div class="pag-linha">
          <span class="pag-label">A</span>
          <button type="button" class="btn-mini btn-menos" onclick="alterarPax(${index}, 'app', -1)">-</button>
          <span id="pax_${index}_app" class="pag-valor">${item.app}</span>
          <button type="button" class="btn-mini btn-mais" onclick="alterarPax(${index}, 'app', 1)">+</button>
        </div>
      </td>
      <td>
        <input type="text" value="${item.obs}" onchange="atualizarCampoTabela(${index}, 'obs', this.value)" placeholder="Obs..." style="font-size:11px; padding:4px; margin-top:0;">
      </td>
    </tr>
  `;
}

// 5. Auxiliares do Registo na Tabela
window.definirHoraAtual = function(index) {
  const agora = new Date();
  const hh = String(agora.getHours()).padStart(2, '0');
  const mm = String(agora.getMinutes()).padStart(2, '0');
  const horaStr = `${hh}:${mm}`;
  document.getElementById(`real_time_${index}`).value = horaStr;
  paragensAtuais[index].horaReal = horaStr;
};

window.alterarPax = function(index, tipo, delta) {
  let val = (paragensAtuais[index][tipo] || 0) + delta;
  if (val < 0) val = 0;
  paragensAtuais[index][tipo] = val;
  document.getElementById(`pax_${index}_${tipo}`).innerText = val;
};

window.atualizarCampoTabela = function(index, campo, valor) {
  paragensAtuais[index][campo] = valor;
};

// 6. Gestão das Paragens Manuais
window.alterarPagManual = function(tipo, delta) {
  pagManual[tipo] = Math.max(0, pagManual[tipo] + delta);
  document.getElementById(`pagManual_${tipo}`).innerText = pagManual[tipo];
  const total = pagManual.D + pagManual.C + pagManual.A;
  document.getElementById("totalPaxManual").innerText = `Total Passageiros: ${total}`;
};

window.adicionarParagem = function() {
  const nome = document.getElementById("paragem_nome").value.trim();
  const tPrevista = document.getElementById("paragem_hora_teorica").value;
  const tReal = document.getElementById("paragem_hora_real").value;
  const obs = document.getElementById("paragem_obs").value.trim();

  if (!nome) {
    alert("Por favor, preencha o nome da paragem manual.");
    return;
  }

  const novoItem = {
    nome: nome,
    horaPrevista: tPrevista || "--",
    horaReal: tReal || "--",
    dinheiro: pagManual.D,
    cartao: pagManual.C,
    app: pagManual.A,
    obs: obs,
    manual: true
  };

  paragensAtuais.push(novoItem);
  renderListaManual();

  // Reset do painel manual
  document.getElementById("paragem_nome").value = "";
  document.getElementById("paragem_hora_teorica").value = "";
  document.getElementById("paragem_hora_real").value = "";
  document.getElementById("paragem_obs").value = "";
  pagManual = { D: 0, C: 0, A: 0 };
  document.getElementById("pagManual_D").innerText = "0";
  document.getElementById("pagManual_C").innerText = "0";
  document.getElementById("pagManual_A").innerText = "0";
  document.getElementById("totalPaxManual").innerText = "Total Passageiros: 0";
};

function renderListaManual() {
  const painel = document.getElementById("painelParagens");
  const manualStops = paragensAtuais.filter(p => p.manual);

  if (manualStops.length === 0) {
    painel.innerHTML = `<em style="color: #6c757d;">Nenhuma paragem manual registada nesta viagem.</em>`;
    return;
  }

  painel.innerHTML = manualStops.map((p, idx) => `
    <div class="estacao-item" style="display:flex; justify-content:space-between; align-items:center;">
      <span><strong>${p.nome}</strong> (Prevista: ${p.horaPrevista} | Real: ${p.horaReal}) [Pax: D:${p.dinheiro} C:${p.cartao} A:${p.app}] - ${p.obs || 'Sem Obs'}</span>
      <button type="button" class="btn-mini btn-menos" onclick="eliminarParagemManual(${idx})" style="width:20px; height:20px; font-size:10px;">X</button>
    </div>
  `).join("");
}

window.eliminarParagemManual = function(idx) {
  let contador = -1;
  const globalIdx = paragensAtuais.findIndex(p => {
    if (p.manual) contador++;
    return p.manual && contador === idx;
  });

  if (globalIdx !== -1) {
    paragensAtuais.splice(globalIdx, 1);
    renderListaManual();
  }
};

// 7. Processamento das Evidências Fotográficas (Base64)
function configurarListenersImagens() {
  configFotos.forEach(item => {
    const el = document.getElementById(item.inputId);
    if (el) {
      el.addEventListener("change", (e) => {
        const file = e.target.files[0];
        if (file) {
          const reader = new FileReader();
          reader.onload = (event) => {
            fotosAtuais[item.inputId] = event.target.result;
            const preview = document.getElementById(item.previewId);
            if (preview) {
              preview.src = event.target.result;
              preview.style.display = "block";
            }
          };
          reader.readAsDataURL(file);
        }
      });
    }
  });
}

// 8. CRUD dos Relatórios Locais (LocalStorage)
window.guardarFichaFinal = function() {
  const avaliadores = document.getElementById("avaliadores").value.trim();
  let carreira = document.getElementById("carreiraSelect").value;
  const sentido = document.getElementById("sentido").value;
  const data_viagem = document.getElementById("data_viagem").value;
  const matricula = document.getElementById("matricula").value.trim();
  const km_esperados = document.getElementById("km_esperados").value.trim();
  const km_efetuados = document.getElementById("km_efetuados").value.trim();

  if (carreira === "manual_custom") {
    const customInput = document.getElementById("carreira_manual_input");
    carreira = customInput ? customInput.value.trim() : "";
    if (!carreira) {
      alert("Por favor, introduza o número e nome da linha personalizada.");
      return;
    }
  }

  // Seções de Inspeção e Qualidade
  const rLimpeza = document.querySelector('input[name="limpeza"]:checked');
  const limpeza = rLimpeza ? rLimpeza.value : "";
  const obs_limpeza = document.getElementById("obs_limpeza").value.trim();
  const materiais_danificados = document.getElementById("materiais_danificados").value.trim();
  const aromatizacao = document.getElementById("aromatizacao").value.trim();
  const climatizacao = document.getElementById("climatizacao").value.trim();
  const graffitis = document.getElementById("graffitis").value.trim();

  const rConducao = document.querySelector('input[name="conducao"]:checked');
  const conducao = rConducao ? rConducao.value : "";

  const atendimento = document.getElementById("atendimento").value.trim();
  const direitos_info = document.getElementById("direitos_info").value.trim();
  const bilingue_info = document.getElementById("bilingue_info").value.trim();
  const ecras_conteudo = document.getElementById("ecras_conteudo").value.trim();
  const wifi = document.getElementById("wifi").value.trim();
  const comentarios_gerais = document.getElementById("comentarios_gerais").value.trim();

  if (!data_viagem || !carreira) {
    alert("Por favor, selecione pelo menos a Data e a Carreira da Viagem.");
    return;
  }

  const novaFicha = {
    id: indiceEdicao === -1 ? Date.now().toString() : fichasGuardadas[indiceEdicao].id,
    avaliadores,
    carreira,
    sentido,
    data_viagem,
    matricula,
    km_esperados,
    km_efetuados,
    limpeza,
    obs_limpeza,
    materiais_danificados,
    aromatizacao,
    climatizacao,
    graffitis,
    conducao,
    atendimento,
    direitos_info,
    bilingue_info,
    ecras_conteudo,
    wifi,
    comentarios_gerais,
    paragens: JSON.parse(JSON.stringify(paragensAtuais)),
    matricula_foto: fotosAtuais.matricula_foto,
    rota_vamus: fotosAtuais.rota_vamus,
    samsung_cycling: fotosAtuais.samsung_cycling,
    foto: fotosAtuais.foto
  };

  if (indiceEdicao === -1) {
    fichasGuardadas.push(novaFicha);
  } else {
    fichasGuardadas[indiceEdicao] = novaFicha;
    cancelarEdicao();
  }

  localStorage.setItem("fichas_vamus", JSON.stringify(fichasGuardadas));
  alert("Relatório de avaliação guardado localmente com sucesso!");
  
  limparFormularioCompleto();
  renderFichasGuardadas();
};

function renderFichasGuardadas() {
  const divLista = document.getElementById("listaRegistos");
  if (fichasGuardadas.length === 0) {
    divLista.innerHTML = `<em style="color:#6c757d;">Não existem fichas de avaliação registadas no sistema.</em>`;
    return;
  }

  divLista.innerHTML = fichasGuardadas.map((f, i) => {
    const totalPax = f.paragens.reduce((sum, p) => sum + (p.dinheiro || 0) + (p.cartao || 0) + (p.app || 0), 0);
    return `
      <div class="item-registo">
        <div class="item-registo-texto">
          <strong>Data:</strong> ${f.data_viagem} | <strong>Linha:</strong> ${f.carreira} (${f.sentido})<br>
          <strong>Avaliador:</strong> ${f.avaliadores || "N/A"} | <strong>Matrícula:</strong> ${f.matricula || "N/A"}<br>
          <strong>Total Passageiros:</strong> ${totalPax} | <strong>Limpeza:</strong> ${f.limpeza || "N/A"}
        </div>
        <button type="button" class="btn-editar" onclick="editarFicha(${i})">Editar</button>
        <button type="button" class="btn-delete" onclick="eliminarFicha(${i})">Eliminar</button>
      </div>
    `;
  }).join("");
}

window.editarFicha = function(i) {
  indiceEdicao = i;
  const f = fichasGuardadas[i];

  document.getElementById("avisoEdicao").style.display = "block";
  document.getElementById("btnCancelarEdicao").style.display = "block";

  document.getElementById("avaliadores").value = f.avaliadores || "";
  
  const select = document.getElementById("carreiraSelect");
  const customInput = document.getElementById("carreira_manual_input");

  if (baseDadosHorarios[f.carreira]) {
    select.value = f.carreira;
    if (customInput) customInput.style.display = "none";
  } else {
    select.value = "manual_custom";
    if (!customInput) {
      const input = document.createElement("input");
      input.type = "text";
      input.id = "carreira_manual_input";
      input.value = f.carreira;
      input.style.marginTop = "8px";
      input.style.display = "block";
      select.parentNode.insertBefore(input, select.nextSibling);
    } else {
      customInput.value = f.carreira;
      customInput.style.display = "block";
    }
  }

  document.getElementById("sentido").value = f.sentido || "Ascendente";
  document.getElementById("data_viagem").value = f.data_viagem || "";
  document.getElementById("matricula").value = f.matricula || "";
  document.getElementById("km_esperados").value = f.km_esperados || "";
  document.getElementById("km_efetuados").value = f.km_efetuados || "";

  if (f.limpeza) {
    const radio = Array.from(document.getElementsByName("limpeza")).find(r => r.value === f.limpeza);
    if (radio) radio.checked = true;
  }
  document.getElementById("obs_limpeza").value = f.obs_limpeza || "";
  document.getElementById("materiais_danificados").value = f.materiais_danificados || "";
  document.getElementById("aromatizacao").value = f.aromatizacao || "";
  document.getElementById("climatizacao").value = f.climatizacao || "";
  document.getElementById("graffitis").value = f.graffitis || "";

  if (f.conducao) {
    const radio = Array.from(document.getElementsByName("conducao")).find(r => r.value === f.conducao);
    if (radio) radio.checked = true;
  }

  document.getElementById("atendimento").value = f.atendimento || "";
  document.getElementById("direitos_info").value = f.direitos_info || "";
  document.getElementById("bilingue_info").value = f.bilingue_info || "";
  document.getElementById("ecras_conteudo").value = f.ecras_conteudo || "";
  document.getElementById("wifi").value = f.wifi || "";
  document.getElementById("comentarios_gerais").value = f.comentarios_gerais || "";

  fotosAtuais = {
    matricula_foto: f.matricula_foto || "",
    rota_vamus: f.rota_vamus || "",
    samsung_cycling: f.samsung_cycling || "",
    foto: f.foto || ""
  };

  configFotos.forEach(item => {
    const preview = document.getElementById(item.previewId);
    if (preview && fotosAtuais[item.inputId]) {
      preview.src = fotosAtuais[item.inputId];
      preview.style.display = "block";
    } else if (preview) {
      preview.style.display = "none";
    }
  });

  paragensAtuais = JSON.parse(JSON.stringify(f.paragens || []));
  const painel = document.getElementById("painelTabelaHorario");

  if (select.value === "manual_custom") {
    painel.innerHTML = `
      <div style="background: #fff3cd; padding: 12px; border-radius: 6px; margin-bottom: 12px; font-weight: bold; border: 1px solid #ffeeba;">
        A editar paragens manuais deste registo personalizado.
      </div>
    `;
  } else {
    painel.innerHTML = `
      <div style="background: #fff3cd; padding: 10px; border-radius: 6px; margin-bottom: 12px; font-weight: bold; border: 1px solid #ffeeba;">
        A editar paragens do registo guardado.
      </div>
      <div class="tabela-wrap">
        <table class="tabela-paragens">
          <thead>
            <tr>
              <th>Paragem</th>
              <th style="width: 70px;">Teórica</th>
              <th style="width: 105px;">Real</th>
              <th style="width: 110px;">Pax (D / C / A)</th>
              <th>Obs / Eventos</th>
            </tr>
          </thead>
          <tbody id="corpoTabelaParagens"></tbody>
        </table>
      </div>
    `;
    const tbody = document.getElementById("corpoTabelaParagens");
    paragensAtuais.forEach((item, index) => {
      tbody.innerHTML += renderizarLinhaParagem(item, index);
    });
  }

  renderListaManual();
  window.scrollTo({ top: 0, behavior: 'smooth' });
};

window.cancelarEdicao = function() {
  indiceEdicao = -1;
  document.getElementById("avisoEdicao").style.display = "none";
  document.getElementById("btnCancelarEdicao").style.display = "none";
  const customInput = document.getElementById("carreira_manual_input");
  if (customInput) {
    customInput.style.display = "none";
    customInput.value = "";
  }
  limparFormularioCompleto();
};

window.eliminarFicha = function(i) {
  if (confirm("Tem a certeza que deseja eliminar esta ficha de avaliação?")) {
    fichasGuardadas.splice(i, 1);
    localStorage.setItem("fichas_vamus", JSON.stringify(fichasGuardadas));
    renderFichasGuardadas();
  }
};

function limparFormularioCompleto() {
  document.getElementById("avaliadores").value = "";
  document.getElementById("carreiraSelect").value = "";
  document.getElementById("sentido").value = "Ascendente";
  document.getElementById("data_viagem").value = "";
  document.getElementById("matricula").value = "";
  document.getElementById("km_esperados").value = "";
  document.getElementById("km_efetuados").value = "";

  const radiosLimpeza = document.getElementsByName("limpeza");
  radiosLimpeza.forEach(r => r.checked = false);
  document.getElementById("obs_limpeza").value = "";
  document.getElementById("materiais_danificados").value = "";
  document.getElementById("aromatizacao").value = "";
  document.getElementById("climatizacao").value = "";
  document.getElementById("graffitis").value = "";

  const radiosConducao = document.getElementsByName("conducao");
  radiosConducao.forEach(r => r.checked = false);

  document.getElementById("atendimento").value = "";
  document.getElementById("direitos_info").value = "";
  document.getElementById("bilingue_info").value = "";
  document.getElementById("ecras_conteudo").value = "";
  document.getElementById("wifi").value = "";
  document.getElementById("comentarios_gerais").value = "";

  configFotos.forEach(item => {
    document.getElementById(item.inputId).value = "";
    const p = document.getElementById(item.previewId);
    if (p) {
      p.src = "";
      p.style.display = "none";
    }
  });

  fotosAtuais = { matricula_foto: "", rota_vamus: "", samsung_cycling: "", foto: "" };
  paragensAtuais = [];
  document.getElementById("painelTabelaHorario").innerHTML = "";
  document.getElementById("painelParagens").innerHTML = `<em style="color: #6c757d;">Nenhuma paragem manual registada nesta viagem.</em>`;
}

// 9. Exportação de Dados para Excel (ExcelJS com Imagens Embutidas)
window.exportarParaExcel = async function() {
  if (fichasGuardadas.length === 0) {
    alert("Não existem fichas gravadas no sistema para exportar.");
    return;
  }

  const workbook = new ExcelJS.Workbook();

  // Separador 1: Relatórios Gerais
  const sheetGerais = workbook.addWorksheet("Avaliações Gerais");
  sheetGerais.columns = [
    { header: "ID Ficha", key: "id", width: 15 },
    { header: "Avaliadores", key: "avaliadores", width: 15 },
    { header: "Carreira / Linha", key: "carreira", width: 25 },
    { header: "Sentido", key: "sentido", width: 15 },
    { header: "Data Viagem", key: "data_viagem", width: 15 },
    { header: "Matrícula", key: "matricula", width: 15 },
    { header: "KMs Esperados", key: "km_esperados", width: 15 },
    { header: "KMs Efetuados", key: "km_efetuados", width: 15 },
    { header: "Inspeção Limpeza", key: "limpeza", width: 25 },
    { header: "Comentários Limpeza", key: "obs_limpeza", width: 30 },
    { header: "Materiais Danificados", key: "materiais_danificados", width: 25 },
    { header: "Aromatização Eficaz", key: "aromatizacao", width: 15 },
    { header: "Climatização Eficaz", key: "climatizacao", width: 15 },
    { header: "Graffitis ou Pastilhas", key: "graffitis", width: 15 },
    { header: "Tipo de Condução", key: "conducao", width: 20 },
    { header: "Atendimento Motorista", key: "atendimento", width: 18 },
    { header: "Info Direitos Passageiros", key: "direitos_info", width: 22 },
    { header: "Info Bilingue", key: "bilingue_info", width: 15 },
    { header: "Conteúdo dos Ecrãs", key: "ecras_conteudo", width: 25 },
    { header: "Wi-Fi Funcional", key: "wifi", width: 15 },
    { header: "Comentários Gerais", key: "comentarios_gerais", width: 40 }
  ];

  sheetGerais.getRow(1).font = { bold: true, color: { argb: "FFFFFF" } };
  sheetGerais.getRow(1).fill = { type: "pattern", pattern: "solid", fgColor: { argb: "007BFF" } };

  fichasGuardadas.forEach(f => {
    sheetGerais.addRow(f);
  });

  // Separador 2: Registos de Passagem detalhados por paragem
  const sheetParagens = workbook.addWorksheet("Passagem nas Paragens");
  sheetParagens.columns = [
    { header: "ID Ficha", key: "id_ficha", width: 15 },
    { header: "Data Viagem", key: "data", width: 15 },
    { header: "Carreira", key: "carreira", width: 25 },
    { header: "Paragem", key: "paragem", width: 30 },
    { header: "Hora Teórica", key: "hora_prevista", width: 15 },
    { header: "Hora Real", key: "hora_real", width: 15 },
    { header: "Desvio (Minutos)", key: "desvio", width: 18 },
    { header: "Pax Dinheiro", key: "dinheiro", width: 15 },
    { header: "Pax Cartão", key: "cartao", width: 15 },
    { header: "Pax App", key: "app", width: 15 },
    { header: "Total Passageiros", key: "total_pax", width: 18 },
    { header: "Observações de Passagem", key: "obs", width: 35 }
  ];

  sheetParagens.getRow(1).font = { bold: true, color: { argb: "FFFFFF" } };
  sheetParagens.getRow(1).fill = { type: "pattern", pattern: "solid", fgColor: { argb: "28A745" } };

  fichasGuardadas.forEach(f => {
    (f.paragens || []).forEach(p => {
      let desvioStr = "--";
      if (p.horaPrevista && p.horaReal && p.horaPrevista !== "--" && p.horaReal !== "--") {
        try {
          const [hp, mp] = p.horaPrevista.split(":").map(Number);
          const [hr, mr] = p.horaReal.split(":").map(Number);
          const minP = hp * 60 + mp;
          const minR = hr * 60 + mr;
          const diff = minR - minP;
          desvioStr = diff > 0 ? `+${diff} min` : `${diff} min`;
        } catch (err) {}
      }

      sheetParagens.addRow({
        id_ficha: f.id,
        data: f.data_viagem,
        carreira: f.carreira,
        paragem: p.nome,
        hora_prevista: p.horaPrevista,
        hora_real: p.horaReal || "--",
        desvio: desvioStr,
        dinheiro: p.dinheiro || 0,
        cartao: p.cartao || 0,
        app: p.app || 0,
        total_pax: (p.dinheiro || 0) + (p.cartao || 0) + (p.app || 0),
        obs: p.obs || ""
      });
    });
  });

  // Separador 3: Evidências Fotográficas
  const sheetFotos = workbook.addWorksheet("Evidências Fotográficas");
  sheetFotos.getColumn(1).width = 28;
  sheetFotos.getColumn(2).width = 28;
  sheetFotos.getColumn(3).width = 28;
  sheetFotos.getColumn(4).width = 28;

  let rowIdx = 1;

  for (const f of fichasGuardadas) {
    sheetFotos.getRow(rowIdx).values = [`Ficha: ${f.carreira} | Data: ${f.data_viagem} | ID: ${f.id}`];
    sheetFotos.getRow(rowIdx).font = { bold: true, size: 12 };
    rowIdx++;

    sheetFotos.getRow(rowIdx).values = ["Foto Matrícula", "Rota Vamus", "Samsung Cycling", "Foto Lateral / Geral"];
    sheetFotos.getRow(rowIdx).font = { bold: true };
    rowIdx++;

    sheetFotos.getRow(rowIdx).height = 150;

    const embutirImagemNoExcel = (base64String, colIndex) => {
      if (!base64String) return;
      try {
        const match = base64String.match(/^data:image\/(\w+);base64,/);
        const extensao = match ? match[1] : "png";
        const cleanBase64 = base64String.replace(/^data:image\/\w+;base64,/, "");

        const imageId = workbook.addImage({
          base64: cleanBase64,
          extension: extensao,
        });

        sheetFotos.addImage(imageId, {
          tl: { col: colIndex - 1, row: rowIdx - 1 },
          ext: { width: 190, height: 190 },
          editAs: 'oneCell'
        });
      } catch (err) {
        console.error("Erro ao embutir imagem: ", err);
      }
    };

    embutirImagemNoExcel(f.matricula_foto, 1);
    embutirImagemNoExcel(f.rota_vamus, 2);
    embutirImagemNoExcel(f.samsung_cycling, 3);
    embutirImagemNoExcel(f.foto, 4);

    rowIdx += 3;
  }

  try {
    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `Relatorio_Vamus_${new Date().toISOString().slice(0,10)}.xlsx`;
    link.click();
  } catch (err) {
    alert("Ocorreu um erro ao exportar o ficheiro Excel: " + err.message);
  }
};